# Worked focus: http-py-credential-provider-design — Inject short-lived credentials through a testable provider with rotation, concurrency, redaction, and failure policy. Demonstrate the result through Python 3.14 urllib, http.client, ssl, typed protocols, and fixture transports.
def worked_http_py_cookies_auth_secrets_3(credential_kind: str, same_origin: bool, redacted: bool) -> dict[str, bool]:
    assert credential_kind in {"cookie", "bearer", "api-key"}
    ambient = credential_kind == "cookie"
    if ambient and not same_origin:
        return {"attach": False, "loggable": False}
    if not redacted:
        return {"attach": False, "loggable": False}
    return {"attach": same_origin or not ambient, "loggable": redacted}

